// Parse the LLM verdict response.
// Enforce: only ELIGIBLE / INELIGIBLE / MANUAL_REVIEW are valid.
// Apply confidence gate: < 0.75 → force MANUAL_REVIEW.
// Detect hedging language → force MANUAL_REVIEW.

const llmResponse = $input.first().json;
const pair = $('Split In Batches').first().json;

let raw = llmResponse.choices?.[0]?.message?.content || '';
raw = raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();

const objStart = raw.indexOf('{');
const objEnd = raw.lastIndexOf('}');

let parsed = { verdict: 'MANUAL_REVIEW', reason: 'LLM response could not be parsed', confidence: 0.0 };

if (objStart !== -1 && objEnd !== -1) {
  try {
    const clean = raw.substring(objStart, objEnd + 1).replace(/,\s*([\]\}])/g, '$1');
    parsed = JSON.parse(clean);
  } catch (e) {
    parsed = { verdict: 'MANUAL_REVIEW', reason: `Parse error: ${e.message}`, confidence: 0.0 };
  }
}

// Enforce valid verdict values
const VALID_VERDICTS = ['ELIGIBLE', 'INELIGIBLE', 'MANUAL_REVIEW'];
if (!VALID_VERDICTS.includes(parsed.verdict)) {
  parsed.verdict = 'MANUAL_REVIEW';
  parsed.reason = `AI returned unknown verdict "${parsed.verdict}": ${parsed.reason}`;
  parsed.confidence = 0.3;
}

// Confidence gate — anything below 0.75 becomes MANUAL_REVIEW
if (typeof parsed.confidence === 'number' && parsed.confidence < 0.75) {
  parsed.verdict = 'MANUAL_REVIEW';
  parsed.reason = `Confidence ${parsed.confidence} below threshold 0.75: ${parsed.reason}`;
}

// Hedging language detection — model is uncertain even if it returned ELIGIBLE
const HEDGE_WORDS = ['unclear', 'possibly', 'might', 'could be', 'uncertain', 'depends', 'perhaps', 'ambiguous'];
const reasonLower = (parsed.reason || '').toLowerCase();
if (parsed.verdict === 'ELIGIBLE' && HEDGE_WORDS.some(w => reasonLower.includes(w))) {
  parsed.verdict = 'MANUAL_REVIEW';
  parsed.reason = `Hedging language detected in reasoning: ${parsed.reason}`;
  parsed.confidence = Math.min(parsed.confidence, 0.5);
}

return [{
  json: {
    ...pair,
    verdict: parsed.verdict,
    reason: parsed.reason,
    verdict_confidence: parsed.confidence,
    verdict_method: 'llm_mistral',
    needs_llm: false,
    decided_at: new Date().toISOString()
  }
}];

function uuid() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

const v = $input.first().json;

// --- Verdict mapping ---
let finalVerdict = 'MANUAL_REVIEW';

if (v.verdict === 'ELIGIBLE') finalVerdict = 'PASS';
else if (v.verdict === 'INELIGIBLE') finalVerdict = 'FAIL';
else if (v.verdict === 'MANUAL_REVIEW') finalVerdict = 'MANUAL_REVIEW';

// --- Safety fallback ---
if (!['PASS', 'FAIL', 'MANUAL_REVIEW'].includes(finalVerdict)) {
  finalVerdict = 'MANUAL_REVIEW';
}

// --- Validate required fields ---
if (!$('Merge').first().json.tender_id) {
  throw new Error('tender_id is missing before POST');
}

return [{
  json: {
    id: uuid(), // or remove if backend generates
    tender_id: $('Merge').first().json.tender_id,
    bidder_id: v.bidder_id,
    criterion_id: v.criterion_id,
    evidence_id: v.evidence_id || null,

    verdict: finalVerdict,
    reason: v.reason || 'No reason provided',
    confidence: v.verdict_confidence ?? 0.5,

    decided_by: v.verdict_method || 'rule_engine',
    version: 1,
    decided_at: v.decided_at || new Date().toISOString()
  }
}];

// All verdict pairs have been processed.
// Build the completion summary.
const webhookData = $('Webhook Trigger').first().json.body;

return [{
  json: {
    tender_id: webhookData.tender_id,
    bidder_ids: webhookData.bidder_ids,
    status: 'verdict_engine_complete',
    completed_at: new Date().toISOString()
  }
}];
